from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json
import logging
from typing import Set

app = Flask(__name__)

# Secure configuration
ALLOWED_TOPICS: Set[str] = {
    'user-events',
    'system-logs',
    'analytics-data',
    'notification-events'
}

# Initialize Kafka producer with secure configuration
producer = KafkaProducer(
    bootstrap_servers=['localhost:9092'],
    value_serializer=lambda v: json.dumps(v).encode('utf-8'),
    security_protocol='SSL',
    ssl_check_hostname=True,
    api_version=(2, 5, 0)
)

def validate_topic(topic: str) -> bool:
    """Validate that topic is in allowed list"""
    return topic in ALLOWED_TOPICS

def sanitize_message(message: str) -> str:
    """Sanitize message to prevent injection attacks"""
    # Remove or escape potentially dangerous characters
    return message.replace('\x00', '').replace('\n', ' ').replace('\r', ' ')

@app.route('/publish', methods=['POST'])
def publish_message():
    try:
        # Get topic and message from request
        topic = request.args.get('topic')
        message = request.args.get('message')
        
        # Validate inputs
        if not topic or not message:
            return jsonify({'error': 'Topic and message are required'}), 400
            
        # Validate topic name
        if not validate_topic(topic):
            return jsonify({'error': 'Topic not allowed'}), 403
            
        # Sanitize message
        sanitized_message = sanitize_message(message)
        
        # Publish message
        future = producer.send(topic, sanitized_message)
        result = future.get(timeout=10)
        
        return jsonify({
            'status': 'success',
            'topic': topic,
            'message_id': str(result)
        })
        
    except Exception as e:
        logging.error(f"Error publishing message: {str(e)}")
        return jsonify({'error': 'Failed to publish message'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)